+// ============================================================================
+// Parallel Chunk Compression (dispatch on macOS)
+// ============================================================================
+
+pub const ParallelCompressor = struct {
+    const CHUNK_SIZE: usize = 256 * 1024; // 256KB chunks
+
+    // Compress multiple chunks in parallel using dispatch on macOS
+    // Returns array of compressed chunks - caller owns all memory
+    pub fn compressChunksParallel(
+        allocator: Allocator,
+        data: []const u8,
+        compression_level: c_int,
+    ) ![][]u8 {
+        if (data.len == 0) return &[_][]u8{};
+
+        // Calculate number of chunks
+        const chunk_count = (data.len + CHUNK_SIZE - 1) / CHUNK_SIZE;
+        const results = try allocator.alloc([]u8, chunk_count);
+        @memset(results, &[_]u8{});
+
+        // Track errors
+        const errors = try allocator.alloc(bool, chunk_count);
+        defer allocator.free(errors);
+        @memset(errors, false);
+
+        if (comptime is_darwin) {
+            // Use dispatch_apply for parallel compression on macOS
+            const queue = dispatch.dispatch_get_global_queue(dispatch.DISPATCH_QUEUE_PRIORITY_HIGH, 0);
+
+            const Context = struct {
+                data: []const u8,
+                results: [][]u8,
+                errors: []bool,
+                alloc: Allocator,
+                level: c_int,
+            };
+            var ctx = Context{
+                .data = data,
+                .results = results,
+                .errors = errors,
+                .alloc = allocator,
+                .level = compression_level,
+            };
+
+            dispatch.dispatch_apply(chunk_count, queue, &dispatchCompress, @ptrCast(&ctx));
+
+            // Check for errors
+            for (errors, 0..) |err, i| {
+                if (err) {
+                    // Free all allocated chunks
+                    for (results) |chunk| {
+                        if (chunk.len > 0) allocator.free(chunk);
+                    }
+                    allocator.free(results);
+                    return error.CompressionFailed;
+                }
+                _ = i;
+            }
+        } else {
+            // Sequential fallback for Linux (TODO: use std.Thread.Pool)
+            for (0..chunk_count) |i| {
+                const start = i * CHUNK_SIZE;
+                const end = @min(start + CHUNK_SIZE, data.len);
+                const chunk = data[start..end];
+
+                const comp = c.libdeflate_alloc_compressor(compression_level);
+                if (comp == null) {
+                    // Free all allocated chunks
+                    for (results[0..i]) |result| {
+                        allocator.free(result);
+                    }
+                    allocator.free(results);
+                    return error.CompressionFailed;
+                }
+                defer c.libdeflate_free_compressor(comp);
+
+                const max_size = c.libdeflate_deflate_compress_bound(comp, chunk.len);
+                var output = allocator.alloc(u8, max_size) catch {
+                    for (results[0..i]) |result| {
+                        allocator.free(result);
+                    }
+                    allocator.free(results);
+                    return error.OutOfMemory;
+                };
+
+                const actual_size = c.libdeflate_deflate_compress(
+                    comp,
+                    chunk.ptr,
+                    chunk.len,
+                    output.ptr,
+                    output.len,
+                );
+
+                if (actual_size == 0) {
+                    allocator.free(output);
+                    for (results[0..i]) |result| {
+                        allocator.free(result);
+                    }
+                    allocator.free(results);
+                    return error.CompressionFailed;
+                }
+
+                results[i] = allocator.realloc(output, actual_size) catch output[0..actual_size];
+            }
+        }
+
+        return results;
+    }
+
+    fn dispatchCompress(context: ?*anyopaque, idx: usize) callconv(.C) void {
+        if (comptime is_darwin) {
+            const Context = struct {
+                data: []const u8,
+                results: [][]u8,
+                errors: []bool,
+                alloc: Allocator,
+                level: c_int,
+            };
+            const ctx = @as(*Context, @ptrCast(@alignCast(context)));
+
+            const start = idx * CHUNK_SIZE;
+            const end = @min(start + CHUNK_SIZE, ctx.data.len);
+            const chunk = ctx.data[start..end];
+
+            // Each thread needs its own compressor
+            const comp = c.libdeflate_alloc_compressor(ctx.level);
+            if (comp == null) {
+                ctx.errors[idx] = true;
+                return;
+            }
+            defer c.libdeflate_free_compressor(comp);
+
+            const max_size = c.libdeflate_deflate_compress_bound(comp, chunk.len);
+            var output = ctx.alloc.alloc(u8, max_size) catch {
+                ctx.errors[idx] = true;
+                return;
+            };
+
+            const actual_size = c.libdeflate_deflate_compress(
+                comp,
+                chunk.ptr,
+                chunk.len,
+                output.ptr,
+                output.len,
+            );
+
+            if (actual_size == 0) {
+                ctx.alloc.free(output);
+                ctx.errors[idx] = true;
+                return;
+            }
+
+            ctx.results[idx] = ctx.alloc.realloc(output, actual_size) catch output[0..actual_size];
+        }
+    }
+
+    // Free all compressed chunks
+    pub fn freeChunks(allocator: Allocator, chunks: [][]u8) void {
+        for (chunks) |chunk| {
+            if (chunk.len > 0) allocator.free(chunk);
+        }
+        allocator.free(chunks);
+    }
+};
